generated_oml:
// Sensing Components
instance MotorShaftEncoder : DTDFVocab:SensingComponent [
    base:desc "Position encoder mounted on the permanent‑magnet synchronous motor shaft, outputting angular position data."
    DTDFVocab:producedData EncoderAngleDataStream
]

instance GearboxOutputEncoder : DTDFVocab:SensingComponent [
    base:desc "Position encoder mounted on the gearbox output shaft of the first axis, providing angular position data."
    DTDFVocab:producedData EncoderAngleDataStream
]

instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Current sensor measuring the motor drive current (I_M) from the first axis."
    DTDFVocab:producedData CurrentPowerDataStream
]

// Data Transmitted
instance EncoderAngleDataStream : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorShaftEncoder, GearboxOutputEncoder
]

instance CurrentPowerDataStream : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

// Processed Data
instance EncoderAngleTrace : DTDFVocab:Data [
    base:desc "Data trace of angular position received from the encoder data stream."
    DTDFVocab:fromData EncoderAngleDataStream
    DTDFVocab:inputTo DigitalShadowProcessingEngine
]

instance CurrentTrace : DTDFVocab:Data [
    base:desc "Data trace of motor drive current received from the current sensor data stream."
    DTDFVocab:fromData CurrentPowerDataStream
    DTDFVocab:inputTo DigitalShadowProcessingEngine
]

instance DerivedTorqueData : DTDFVocab:Data [
    base:desc "Computed torque derived from motor current and encoder angle data."
    DTDFVocab:inputTo SimulinkExecutionEngine
]

instance DerivedAngularVelocityData : DTDFVocab:Data [
    base:desc "Computed angular velocity derived from encoder angle data."
    DTDFVocab:inputTo DigitalShadowProcessingEngine
]

instance DerivedAngularAccelerationData : DTDFVocab:Data [
    base:desc "Computed angular acceleration derived from encoder angle data."
    DTDFVocab:inputTo DigitalShadowProcessingEngine
]

instance FrictionParameterEstimateData : DTDFVocab:Data [
    base:desc "Estimated friction model parameters inferred from continuous identification."
    DTDFVocab:inputTo SimulinkExecutionEngine
]

// Models
instance MotorGearboxDynamicsSimulinkModel : DTDFVocab:Model [
    base:desc "Simulink model of the permanent‑magnet synchronous motor, gearwheel gearbox, and cycloidal gearbox, including Coulomb‑Viscous, Stribeck, Dahl, and LuGre friction models."
    DTDFVocab:inputTo SimulinkExecutionEngine
]

instance FrictionParameterIdentificationModel : DTDFVocab:Model [
    base:desc "Simulink model used for multi‑physics‑wide continuous identification of joint friction parameters."
    DTDFVocab:inputTo SimulinkExecutionEngine
]

// Enablers
instance MQTTGateway : DTDFVocab:Enabler [
    base:desc "MQTT gateway that streams sensor data from the robot controller to the digital shadow."
    DTDFVocab:enables RealTimeVisualizationService
]

instance SimulinkExecutionEngine : DTDFVocab:Enabler [
    base:desc "Execution engine for running Simulink simulation models of motor and gearbox dynamics."
    DTDFVocab:enables FrictionParameterIdentificationService, ControlOptimizationService
]

instance DigitalShadowProcessingEngine : DTDFVocab:Enabler [
    base:desc "Processing engine that ingests raw sensor data and computes derived metrics such as torque, angular velocity, and friction parameters."
    DTDFVocab:enables RealTimeVisualizationService
]

instance AssetAdministrationShell : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell that provides metadata, traceability, and governance for the digital twin data set."
    DTDFVocab:enables DataGovernanceService
]

instance DashboardVisualizationComponent : DTDFVocab:Enabler [
    base:desc "Dashboard component that visualizes real‑time comparison between measured and simulated torque and angular velocity."
    DTDFVocab:enables RealTimeVisualizationService
]

// Services
instance RealTimeVisualizationService : DTDFVocab:Service [
    base:desc "Service providing real‑time visualization of measured versus simulated torque and angular velocity."
    DTDFVocab:provides DataComparisonInsight
]

instance FrictionParameterIdentificationService : DTDFVocab:Service [
    base:desc "Service performing continuous, multi‑physics‑aware identification of joint friction parameters."
    DTDFVocab:provides FrictionParametersInsight, ControlGainsAdjustmentAction
]

instance ControlOptimizationService : DTDFVocab:Service [
    base:desc "Service facilitating control strategy optimization by updating friction model parameters and advising control gain adjustments."
    DTDFVocab:provides SelectFrictionModelAction, MaintenancePlanningAction
]

// Data Governance Service
instance DataGovernanceService : DTDFVocab:Service [
    base:desc "Service managing governance, metadata, and traceability of the digital twin data."
]

// Insights and Actions
instance DataComparisonInsight : DTDFVocab:Insight [
    base:desc "Insight comparing real‑time measured torque and angular velocity with simulated outputs."
]

instance FrictionParametersInsight : DTDFVocab:Insight [
    base:desc "Insight indicating best‑fit friction model parameters for the current operating conditions."
]

instance ControlGainsAdjustmentAction : DTDFVocab:Action [
    base:desc "Action to adjust motor controller gains based on identified friction parameters."
    DTDFVocab:IsAutomatic true
]

instance SelectFrictionModelAction : DTDFVocab:Action [
    base:desc "Action to select or update the friction model (e.g., Coulomb‑Viscous, Stribeck)."
    DTDFVocab:IsAutomatic false
]

instance MaintenancePlanningAction : DTDFVocab:Action [
    base:desc "Action recommending maintenance activities based on observed friction behavior."
    DTDFVocab:IsAutomatic false
]

// Environment
instance RobotControllerEnvironment : DTDFVocab:Environment [
    base:desc "Robot controller environment that hosts the sensors and MQTT gateway."
]

// Physical Components
instance PermanentMagnetSynchronousMotor : DTDFVocab:Component [
    base:desc "Permanent‑magnet synchronous motor constituting the first axis of the MABI MAX 100 industrial robot."
]

instance GearwheelGearbox : DTDFVocab:Component [
    base:desc "Gearwheel gearbox connecting the motor shaft to the cycloidal gearbox in the first axis."
]

instance CycloidalGearbox : DTDFVocab:Component [
    base:desc "Cycloidal gearbox providing high‑torque reduction for the first axis."
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Continuous, real‑time data collection and processing via MQTT; friction identification occurs during normal robot operation without explicit time‑step intervals specified."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A single digital shadow instance for the first axis, comprising the structural engine model, simulation models, sensor and simulation data traces, a processing component that executes the simulation models on real data, and a dashboard for monitoring and visualization, all coordinated via the AAS and MQTT publish/subscribe."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Includes the manufactured phase through detailed engineering and simulation models, and the operated phase via continuous data‑driven updates of friction models during runtime."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Traceability of each data trace to its generating source and processing model; continuous comparison of simulated vs measured torque/velocity to validate friction models; use of both white‑box analytical and black‑box data‑driven models to capture complex friction dynamics; recognition of parameter drift due to wear, temperature, load, and time, necessitating online identification."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "MQTT protocol over TCP/IP for streaming sensor data from the Siemens SINUMERIK 840D SL controller to the digital shadow; the AAS provides semantic metadata and service interfaces; no explicit physical actuator communication described."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Uses SysML for system architecture and mathematical behavior modeling; employs the Asset Administration Shell (standardized by IEC 62832); follows MBSE practices (RFLP, SPES, SMArDT) and modeling notations such as ACME, AADL, and MontiArc when applicable."
]
